import { Avatar, Text, Grid } from "@nextui-org/react";
import React from "react";

export default function Testimonial() {
  return (
    <Grid.Container gap={2} justify="center" css={{ mt: "50px" }}>
      <Avatar
        src="https://i.pravatar.cc/150?u=a04258114e29026702d"
        css={{ size: "$20" }}
      />
      <Text small css={{ padding: "10px" }}>
        Saad is a fantastic person to work with, and is not only a multi-skilled
        and insightful colleague, but also an inspiring strategist. Very good
        person. Great employee with a very strong problem solving skills. Saad
        is an asset to any company.
      </Text>
    </Grid.Container>
  );
}
